const trigger = $('Telegram Trigger').item.json;
const mensaje = trigger.message.text.trim();
const chat_id = trigger.message.chat.id;
const telegram_user = String(trigger.message.from.id);

const sd = $getWorkflowStaticData('global');
if (!sd[telegram_user]) {
  sd[telegram_user] = { estado: 'MENU', datos: {} };
}
const session = sd[telegram_user];

return [{
  json: {
    estado: session.estado,
    mensaje: mensaje,
    datos: session.datos,
    chat_id: chat_id,
    telegram_user: telegram_user
  }
}];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

const tipos = {
  '1': 'Soporte técnico',
  '2': 'Solicitud administrativa',
  '3': 'Consulta general'
};

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];
session.datos = session.datos || {};
session.datos.tipo = tipos[mensaje];
session.estado = 'PRIORIDAD';

return [{
  json: {
    estado: session.estado,
    datos: session.datos,
    chat_id: $json.chat_id,
    telegram_user: telegram_user,
    mensaje: `\u2705 Tipo seleccionado: *${session.datos.tipo}*`
  }
}];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

const prioridades = { '1': 'Alta', '2': 'Media', '3': 'Baja' };

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];

if (mensaje === '9') {
  session.estado = 'MENU'; session.datos = {};
  return [{ json: { estado: session.estado, datos: {}, chat_id: $json.chat_id,
    telegram_user, cancelado: true, invalido: false,
    mensaje: '\u274c Solicitud cancelada\\\\. Volviendo al men\u00fa principal\\\\.' } }];
}

if (!prioridades[mensaje]) {
  return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
    telegram_user, cancelado: false, invalido: true,
    mensaje: '\u26a0\ufe0f Opci\u00f3n no v\u00e1lida\\\\. Por favor escribe 1, 2, 3 o 9 para cancelar\\\\.' } }];
}

session.datos = session.datos || {};
session.datos.prioridad = prioridades[mensaje];
session.estado = 'DESCRIPCION';

return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
  telegram_user, cancelado: false, invalido: false,
  mensaje: `\u2705 Prioridad seleccionada: *${session.datos.prioridad}*` } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];

if (mensaje === '9') {
  session.estado = 'MENU'; session.datos = {};
  return [{ json: { estado: session.estado, datos: {}, chat_id: $json.chat_id,
    telegram_user, cancelado: true, invalido: false,
    mensaje: '\u274c Solicitud cancelada\\\\. Volviendo al men\u00fa principal\\\\.' } }];
}

if (!mensaje || mensaje.trim().length < 5) {
  return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
    telegram_user, cancelado: false, invalido: true,
    mensaje: '\u26a0\ufe0f La descripci\u00f3n es muy corta\\\\. Por favor s\u00e9 m\u00e1s espec\u00edfico\\\\.' } }];
}

session.datos = session.datos || {};
session.datos.descripcion = mensaje.trim();
session.estado = 'CONFIRMACION';

return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
  telegram_user, cancelado: false, invalido: false,
  mensaje: '\u2705 Descripci\u00f3n registrada\\\\.' } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $('Obtener Estado Sesi\u00f3n').item.json.telegram_user;

sd[telegram_user] = { estado: 'MENU', datos: {} };

return [{ json: {
  chat_id: $('Obtener Estado Sesi\u00f3n').item.json.chat_id,
  telegram_user: telegram_user,
  mensaje: 'Sesi\u00f3n limpiada correctamente'
} }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;

if (sd[telegram_user]) { sd[telegram_user] = { estado: 'MENU', datos: {} }; }

return [{ json: {
  chat_id: $json.chat_id,
  telegram_user: telegram_user,
  mensaje: '\u274c Solicitud cancelada\\\\. Volviendo al men\u00fa principal\\\\.'
} }];

const chat_id = $('Obtener Estado Sesi\u00f3n').item.json.chat_id;
const items = $input.all().filter(i => i.json.estado !== 'Cerrado');

if (!items || items.length === 0) {
  return [{ json: { chat_id: chat_id,
    mensaje: '\ud83d\udcad No tienes solicitudes abiertas en este momento\\.\n\nEscribe *1* para crear una nueva solicitud\\.' } }];
}

let texto = '\ud83d\udccb *Tus solicitudes activas:*\n\n';
for (const item of items) {
  const t = item.json;
  texto += `\ud83d\udd16 *ID:* ${t.id_ticket}\n`;
  texto += `\ud83c\udff7\ufe0f *Tipo:* ${t.tipo}\n`;
  texto += `\u26a1 *Prioridad:* ${t.prioridad}\n`;
  texto += `\ud83d\udcca *Estado:* ${t.estado}\n`;
  texto += `\ud83d\udcc5 *Fecha:* ${t.fecha_creacion}\n\n`;
}
texto += 'Escribe cualquier n\u00famero para volver al men\u00fa principal\\.';
return [{ json: { chat_id: chat_id, mensaje: texto } }];

const items = $input.all();
const chat_id = $('Obtener Estado Sesión').item.json.chat_id;

// Si no hay tickets
if (!items || items.length === 0) {
  return [{
    json: {
      chat_id: chat_id,
      mensaje: '📭 Aún no tienes solicitudes registradas\\.\n\nEscribe *1* para crear tu primera solicitud\\.'
    }
  }];
}

// Formateamos la lista completa
let texto = `📋 *Todas tus solicitudes:* ${items.length} en total\n\n`;

for (const item of items) {
  const t = item.json;

  // Emoji según estado
  const estadoEmoji = {
    'Abierto': '🟡',
    'En proceso': '🔵',
    'Cerrado': '✅'
  }[t.estado] || '⚪';

  texto += `🔖 *ID:* ${t.id_ticket}\n`;
  texto += `🏷️ *Tipo:* ${t.tipo}\n`;
  texto += `⚡ *Prioridad:* ${t.prioridad}\n`;
  texto += `${estadoEmoji} *Estado:* ${t.estado}\n`;
  texto += `📅 *Fecha:* ${t.fecha_creacion}\n`;
  texto += `\n`;
}

texto += 'Escribe cualquier número para volver al menú principal\\.';

return [{
  json: {
    chat_id: chat_id,
    mensaje: texto
  }
}];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
sd[telegram_user].estado = 'TIPO';
sd[telegram_user].datos = {};

return [{ json: {
  chat_id: $json.chat_id,
  telegram_user: telegram_user,
  estado: 'TIPO',
  datos: {}
} }];
